/**
 * @summary Verify secret code and return full document info
 */
export const getVerifyCodeUrl = (uuid: string) => {
  return `/api/verify/${uuid}/check`;
};

export const verifyCode = async (
  uuid: string,
  verifyCodeRequest: VerifyCodeRequest,
  options?: RequestInit,
): Promise<VerifyResult> => {
  return customFetch<VerifyResult>(getVerifyCodeUrl(uuid), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(verifyCodeRequest),
  });
};

export const getVerifyCodeMutationOptions = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof verifyCode>>,
    TError,
    { uuid: string; data: BodyType<VerifyCodeRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof verifyCode>>,
  TError,
  { uuid: string; data: BodyType<VerifyCodeRequest> },
  TContext
> => {
  const mutationKey = ["verifyCode"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof verifyCode>>,
    { uuid: string; data: BodyType<VerifyCodeRequest> }
  > = (props) => {
    const { uuid, data } = props ?? {};

    return verifyCode(uuid, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type VerifyCodeMutationResult = NonNullable<
  Awaited<ReturnType<typeof verifyCode>>
>;
export type VerifyCodeMutationBody = BodyType<VerifyCodeRequest>;
export type VerifyCodeMutationError = ErrorType<ErrorResponse>;

/**
 * @summary Verify secret code and return full document info
 */
export const useVerifyCode = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof verifyCode>>,
    TError,
    { uuid: string; data: BodyType<VerifyCodeRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof verifyCode>>,
  TError,
  { uuid: string; data: BodyType<VerifyCodeRequest> },
  TContext
> => {
  return useMutation(getVerifyCodeMutationOptions(options));
};

